query ListCampaignOrders($first: Int, $status: CampaignStatus) {
  campaignOrdersConnection(
    first: $first
    where: { status: $status }
  ) {
    edges {
      node {
        id
        name
        status
        budget
        startDate
        endDate
        createdAt
        campaigns {
          id
          name
          type
          budgetTotal
        }
      }
    }
    aggregate {
      count
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}
